package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisAsJsonObject() throws Exception {
    // Create a mock of JsonElement with real method calls by default
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    // Stub isJsonObject to return true
    when(element.isJsonObject()).thenReturn(true);

    // Use reflection to forcibly set the class of the mock to JsonObject so that cast in getAsJsonObject works
    // Because getAsJsonObject casts "this" to JsonObject, we must make the mock appear as JsonObject at runtime.
    // This hack is needed because JsonObject is final and cannot be subclassed here.

    // The mock's class is a proxy, so we replace its class with JsonObject.class via reflection on the mock's invocation handler.
    // But this is complicated, so simpler approach: mock JsonObject and spy on it to override isJsonObject() to true,
    // then call getAsJsonObject on this spy.

    JsonObject jsonObjectMock = mock(JsonObject.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    JsonObject spyJsonObject = spy(jsonObjectMock);
    doReturn(true).when(spyJsonObject).isJsonObject();

    JsonObject result = spyJsonObject.getAsJsonObject();
    assertSame(spyJsonObject, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(element.isJsonObject()).thenReturn(false);

    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonObject);
    assertTrue(exception.getMessage().startsWith("Not a JSON Object: "));
  }
}
